hooks.command:
python3 -c "
import os, json, subprocess, sys
try:
    inp = json.loads(os.environ.get('CLAUDE_TOOL_INPUT', '{}'))
    f = inp.get('file_path', '')
    if f.endswith(('compose.yaml', 'compose.yml', 'docker-compose.yaml', 'docker-compose.yml')):
        result = subprocess.run(['docker', 'compose', '-f', f, 'config', '--quiet'], capture_output=True, text=True)
        if result.returncode != 0:
            print(f'[nas-docker-helper] compose-validate WARNING: {f} failed validation:', file=sys.stderr)
            print(result.stderr.strip(), file=sys.stderr)
        else:
            print(f'[nas-docker-helper] compose-validate OK: {f} is valid')
except Exception as e:
    print(f'[nas-docker-helper] compose-validate error: {e}', file=sys.stderr)
"
